data.query:
query Collections($first: Int!, $after: String, $query: String) {
    collections(first: $first, after: $after, query: $query, sortKey: UPDATED_AT) {
        nodes {
            id
            title
            handle
            descriptionHtml
            updatedAt
            sortOrder
            templateSuffix
        }
        pageInfo {
            hasNextPage
            endCursor
        }
    }
}

